import React, { useState, useEffect, useCallback, useRef } from 'react';
import { useNavigate, useSearchParams } from 'react-router-dom';
import { ShopCardHorizontal } from '../components/common/ShopCard';
import { SkeletonShopCardHorizontal } from '../components/common/SkeletonCard';
import { getShops } from '../utils/api';
import { useLocation } from '../context/LocationContext';
import { Search, X, MapPin, SlidersHorizontal, Star, Compass, Sparkles, Clock, ArrowUpDown, Mic } from 'lucide-react';
import '../styles/Search.css';

const CATEGORIES = ['All', 'Food', 'Services', 'Shops', 'Products'];
const RATING_OPTIONS = [
  { label: 'Any rating', value: 0 },
  { label: '3+ stars',   value: 3 },
  { label: '4+ stars',   value: 4 },
  { label: '4.5+ stars', value: 4.5 },
];
const SORT_OPTIONS = [
  { label: 'Relevance',    value: 'relevance' },
  { label: 'Top Rated',    value: 'rating' },
  { label: 'Most Reviews', value: 'reviews' },
  { label: 'Newest',       value: 'newest' },
];

const MAX_RECENT = 5;

const getRecentSearches = () => {
  try { return JSON.parse(localStorage.getItem('qv_recent_searches') || '[]'); }
  catch { return []; }
};

const saveRecentSearch = (q) => {
  if (!q.trim()) return;
  const prev = getRecentSearches().filter(s => s !== q);
  localStorage.setItem('qv_recent_searches', JSON.stringify([q, ...prev].slice(0, MAX_RECENT)));
};

const SearchPage = () => {
  const navigate = useNavigate();
  const [searchParams, setSearchParams] = useSearchParams();
  const { location } = useLocation();

  const [query, setQuery]           = useState('');
  const [category, setCategory]     = useState('All');
  const [minRating, setMinRating]   = useState(0);
  const [sortBy, setSortBy]         = useState('relevance');
  const [shops, setShops]           = useState([]);
  const [loading, setLoading]       = useState(false);
  const [loadingMore, setLoadingMore] = useState(false);
  const [hasMore, setHasMore]       = useState(false);
  const [page, setPage]             = useState(1);
  const [showFilters, setFilters]   = useState(false);
  const [resultError, setResultError] = useState('');
  const [recentSearches, setRecentSearches] = useState(getRecentSearches);

  const [isListening, setIsListening] = useState(false);
  const [suggestions, setSuggestions]       = useState([]);
  const [showSuggest, setShowSuggest]       = useState(false);
  const [suggestLoading, setSuggestLoading] = useState(false);

  const suggestRef   = useRef(null);
  const inputRef     = useRef(null);
  const debounceRef  = useRef(null);
  const suggestDebRef = useRef(null);
  const urlSyncRef = useRef(null);
  const sentinelRef = useRef(null);
  const pagingRef = useRef(false);

  const handleVoiceSearch = () => {
    const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;
    if (!SpeechRecognition) {
      alert('Voice search is not supported in this browser.');
      return;
    }
    const recognition = new SpeechRecognition();
    recognition.lang = 'en-IN';
    recognition.onstart = () => setIsListening(true);
    recognition.onend = () => setIsListening(false);
    recognition.onresult = (event) => {
      const transcript = event.results[0][0].transcript;
      setQuery(transcript);
      handleSearchSubmit(transcript);
    };
    recognition.start();
  };

  const highlightText = (text, highlight) => {
    if (!highlight.trim()) return text;
    const parts = text.split(new RegExp(`(${highlight})`, 'gi'));
    return (
      <span>
        {parts.map((part, i) => 
          part.toLowerCase() === highlight.toLowerCase() 
            ? <mark key={i} className="search-highlight">{part}</mark> 
            : part
        )}
      </span>
    );
  };

  const fetchPage = useCallback(async (q, cat, rating, sort, targetPage, replace = false) => {
    if (!replace && (pagingRef.current || !hasMore)) return;
    if (!replace) pagingRef.current = true;

    replace ? setLoading(true) : setLoadingMore(true);
    setResultError('');
    try {
      const { data } = await getShops({
        search: q,
        category: cat,
        minRating: rating || undefined,
        sortBy: sort !== 'relevance' ? sort : undefined,
        page: targetPage,
        limit: 10
      });
      const incoming = data.shops || [];
      setShops(prev => (replace ? incoming : [...prev, ...incoming]));
      setPage(targetPage);
      setHasMore(targetPage < (data.pages || 1));
    } catch {
      if (replace) setShops([]);
      setResultError('Could not load more shops. Please retry.');
    } finally {
      replace ? setLoading(false) : setLoadingMore(false);
      pagingRef.current = false;
    }
  }, [hasMore]);

  const search = useCallback(async (q, cat, rating, sort) => {
    setPage(1);
    setHasMore(false);
    setLoadingMore(false);
    await fetchPage(q, cat, rating, sort, 1, true);
  }, [fetchPage]);

  const fetchSuggestions = useCallback(async (q) => {
    if (q.length < 2) { setSuggestions([]); return; }
    setSuggestLoading(true);
    try {
      const { data } = await getShops({ search: q, limit: 6 });
      setSuggestions(data.shops || []);
    } catch { setSuggestions([]); }
    finally { setSuggestLoading(false); }
  }, []);

  useEffect(() => {
    clearTimeout(debounceRef.current);
    debounceRef.current = setTimeout(() => {
      let finalCat = category;
      let finalRating = minRating;
      let finalSort = sortBy;
      let cleanQuery = query.toLowerCase();

      // Simple NLP logic
      if (cleanQuery.includes('top ') || cleanQuery.includes('best ') || cleanQuery.includes('highly rated')) {
        finalRating = 4;
      }
      if (cleanQuery.includes('new ') || cleanQuery.includes('latest ')) {
        finalSort = 'newest';
      }
      if (cleanQuery.includes('popular ')) {
        finalSort = 'reviews';
      }
      
      // Auto-category detection
      const foundCat = CATEGORIES.find(c => c !== 'All' && cleanQuery.includes(c.toLowerCase()));
      if (foundCat) finalCat = foundCat;

      search(query, finalCat, finalRating, finalSort);
    }, 350);
    return () => clearTimeout(debounceRef.current);
  }, [query, category, minRating, sortBy, search]);

  useEffect(() => {
    clearTimeout(suggestDebRef.current);
    suggestDebRef.current = setTimeout(() => fetchSuggestions(query), 200);
    return () => clearTimeout(suggestDebRef.current);
  }, [query, fetchSuggestions]);

  useEffect(() => {
    const h = e => { if (suggestRef.current && !suggestRef.current.contains(e.target)) setShowSuggest(false); };
    document.addEventListener('mousedown', h);
    return () => document.removeEventListener('mousedown', h);
  }, []);

  useEffect(() => {
    if (loading || !hasMore || !sentinelRef.current) return undefined;
    const observer = new IntersectionObserver(
      (entries) => {
        const [entry] = entries;
        if (entry.isIntersecting) {
          fetchPage(query, category, minRating, sortBy, page + 1, false);
        }
      },
      { root: null, rootMargin: '220px 0px', threshold: 0.01 }
    );
    observer.observe(sentinelRef.current);
    return () => observer.disconnect();
  }, [loading, hasMore, page, fetchPage, query, category, minRating, sortBy]);

  const activeFilters = (category !== 'All' ? 1 : 0) + (minRating > 0 ? 1 : 0) + (sortBy !== 'relevance' ? 1 : 0);

  const handleSearchSubmit = (q) => {
    saveRecentSearch(q);
    setRecentSearches(getRecentSearches());
    setShowSuggest(false);
  };
  const total = shops.length;
  const locationLabel = location.city ? `${location.area ? location.area + ', ' : ''}${location.city}` : 'Location not set';
  const externalQuery = searchParams.get('q') || '';

  useEffect(() => {
    setQuery(prev => (prev === externalQuery ? prev : externalQuery));
  }, [externalQuery]);

  useEffect(() => {
    clearTimeout(urlSyncRef.current);
    urlSyncRef.current = setTimeout(() => {
      if (query === externalQuery) return;
      const nextParams = new URLSearchParams(searchParams);
      if (query.length > 0) {
        nextParams.set('q', query);
      } else {
        nextParams.delete('q');
      }
      setSearchParams(nextParams, { replace: true });
    }, 180);

    return () => clearTimeout(urlSyncRef.current);
  }, [query, externalQuery, searchParams, setSearchParams]);

  return (
    <div className="search-page">
      <div className="content-container">
        <section className="search-hero">
          <div>
            <p className="search-hero-eyebrow">Smart discovery</p>
            <h1 className="search-hero-title">Find trusted shops faster</h1>
            <p className="search-hero-sub">
              Explore top-rated places with live filters, local ranking, and instant results.
            </p>
          </div>
          <div className="search-hero-pill">
            <Compass size={14} />
            {locationLabel}
          </div>
        </section>

        {/* ── Search bar ── */}
        <div className="search-top">
          <div className="search-bar-wrap" ref={suggestRef}>
            <div className="search-bar">
              <Search size={17} className="search-bar-icon" />
              <input
                ref={inputRef}
                className="search-bar-input"
                type="text"
                placeholder="Search shops, areas, categories..."
                value={query}
                onChange={e => { setQuery(e.target.value); setShowSuggest(true); }}
                onFocus={() => setShowSuggest(true)}
                onKeyDown={e => { if (e.key === 'Enter') handleSearchSubmit(query); }}
                aria-label="Search shops"
                autoFocus
                autoComplete="off"
              />
              <div className="search-bar-actions">
                {query && (
                  <button className="search-clear" onClick={() => { setQuery(''); setSuggestions([]); inputRef.current?.focus(); }} aria-label="Clear">
                    <X size={15} />
                  </button>
                )}
                <button 
                  className={`search-voice-btn ${isListening ? 'listening' : ''}`} 
                  onClick={handleVoiceSearch}
                  title="Voice Search"
                >
                  <Mic size={17} />
                </button>
              </div>
            </div>

            {/* Autocomplete */}
            {showSuggest && (
              <div className="suggest-dropdown">
                {/* Recent searches (shown when query is empty) */}
                {query.length < 2 && recentSearches.length > 0 && (
                  <>
                    <div className="suggest-section-label">
                      <Clock size={12} /> Recent searches
                    </div>
                    {recentSearches.map(s => (
                      <button key={s} className="suggest-item suggest-item--recent" onClick={() => { setQuery(s); handleSearchSubmit(s); }}>
                        <span className="suggest-emoji"><Clock size={14} /></span>
                        <span className="suggest-info">
                          <span className="suggest-name">{s}</span>
                        </span>
                        <button
                          className="suggest-remove"
                          onClick={e => {
                            e.stopPropagation();
                            const updated = recentSearches.filter(r => r !== s);
                            localStorage.setItem('qv_recent_searches', JSON.stringify(updated));
                            setRecentSearches(updated);
                          }}
                          aria-label="Remove"
                        >
                          <X size={12} />
                        </button>
                      </button>
                    ))}
                  </>
                )}

                {/* Live suggestions */}
                {query.length >= 2 && (
                  suggestLoading ? (
                    <div className="suggest-loading">Searching…</div>
                  ) : suggestions.length === 0 ? (
                    <div className="suggest-empty">No results for "{query}"</div>
                  ) : (
                    <>
                      <div className="suggest-section-label">
                        <Search size={12} /> Suggestions
                      </div>
                      {suggestions.map(shop => (
                        <button key={shop._id} className="suggest-item" onClick={() => { handleSearchSubmit(shop.name); navigate(`/shop/${shop._id}`); }}>
                          <span className="suggest-emoji">
                            {shop.category === 'Food' ? '🍽️' : shop.category === 'Services' ? '🔧' : shop.category === 'Shops' ? '🛍️' : '📦'}
                          </span>
                          <span className="suggest-info">
                            <span className="suggest-name">{highlightText(shop.name, query)}</span>
                            <span className="suggest-meta">{highlightText(`${shop.category} · ${shop.area}, ${shop.city}`, query)}</span>
                          </span>
                          {shop.averageRating > 0 && (
                            <span className="suggest-rating"><Star size={11} fill="var(--accent)" color="var(--accent)" /> {shop.averageRating.toFixed(1)}</span>
                          )}
                        </button>
                      ))}
                    </>
                  )
                )}
              </div>
            )}
          </div>

          {/* Meta row */}
          <div className="search-meta">
            <span className="search-loc"><MapPin size={13} /> {total} result{total === 1 ? '' : 's'}</span>
            <button className={`filter-btn ${showFilters ? 'active' : ''}`} onClick={() => setFilters(p => !p)}>
              <SlidersHorizontal size={14} />
              Filters
              {activeFilters > 0 && <span className="filter-count">{activeFilters}</span>}
            </button>
          </div>
        </div>

        {/* ── Filters ── */}
        {showFilters && (
          <div className="filters-panel">
            <div className="filter-row">
              <span className="filter-row-label">Category</span>
              <div className="filter-chips">
                {CATEGORIES.map(c => (
                  <button key={c} className={`filter-chip ${category === c ? 'active' : ''}`} onClick={() => setCategory(c)}>{c}</button>
                ))}
              </div>
            </div>
            <div className="filter-row">
              <span className="filter-row-label">Min Rating</span>
              <div className="filter-chips">
                {RATING_OPTIONS.map(opt => (
                  <button key={opt.value} className={`filter-chip ${minRating === opt.value ? 'active' : ''}`} onClick={() => setMinRating(opt.value)}>
                    {opt.label}
                  </button>
                ))}
              </div>
            </div>
            <div className="filter-row">
              <span className="filter-row-label"><ArrowUpDown size={11} style={{ display: 'inline', marginRight: 4 }} />Sort By</span>
              <div className="filter-chips">
                {SORT_OPTIONS.map(opt => (
                  <button key={opt.value} className={`filter-chip ${sortBy === opt.value ? 'active' : ''}`} onClick={() => setSortBy(opt.value)}>
                    {opt.label}
                  </button>
                ))}
              </div>
            </div>
            {activeFilters > 0 && (
              <button className="clear-filters" onClick={() => { setCategory('All'); setMinRating(0); setSortBy('relevance'); }}>Clear all filters</button>
            )}
          </div>
        )}

        {/* ── Results ── */}
        <div className="search-results">
          {activeFilters > 0 && (
            <div className="search-active-filters">
              <Sparkles size={14} />
              <span>
                Active: {category !== 'All' ? category : 'All categories'}
                {minRating > 0 ? ` · ${minRating}+ stars` : ''}
              </span>
            </div>
          )}

          {loading ? (
            <div>
              {[1,2,3,4].map(i => <SkeletonShopCardHorizontal key={i} />)}
            </div>
          ) : (
            <>
              {shops.length > 0 && (
                <section>
                  <div className="results-section-label">
                    <Sparkles size={13} /> Top Rated Discoveries
                    <span className="results-count">{shops.length}</span>
                  </div>
                  {shops.map(shop => <ShopCardHorizontal key={shop._id} shop={shop} />)}
                </section>
              )}

              {resultError && (
                <div className="search-load-error">
                  {resultError}
                  <button onClick={() => fetchPage(query, category, minRating, page + 1, false)}>Retry</button>
                </div>
              )}

              {loadingMore && (
                <div className="search-loading-more">
                  <div className="spinner" />
                  <span>Loading more top rated shops...</span>
                </div>
              )}

              {!hasMore && shops.length > 0 && (
                <div className="search-end-feed">You have reached the end of results.</div>
              )}

              <div ref={sentinelRef} className="search-feed-sentinel" aria-hidden="true" />

              {total === 0 && (
                <div className="empty-state" style={{ marginTop: 32 }}>
                  <div className="empty-state-icon"><Search size={28} /></div>
                  <h3>Nothing found</h3>
                  <p>{query ? `No shops match "${query}". Try a different name or area.` : 'Start typing to search for shops near you.'}</p>
                </div>
              )}
            </>
          )}
        </div>
      </div>
    </div>
  );
};

export default SearchPage;
